import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return depot_node  # Return to depot if no unvisited nodes.

    # Distance to all nodes from current node
    distances = distance_matrix[current_node]

    # Check if waiting is a viable option by validating if nearby nodes are being approached by other trucks
    near_nodes = np.argsort(distances)  # Nodes sorted by distance from current
    for node in near_nodes:
        if node in unvisited_nodes and node in truck_nodes:
            # If a close node is being targeted by another truck, we consider waiting.
            if distances[node] < np.min([distance_matrix[current_node, n] for n in unvisited_nodes if n not in truck_nodes]):
